SELECT ?year ?populationGrowth WHERE {
  ?country wdt:P31 wd:Q6256;  # instance of country
           wdt:P17 wd:Q183;  # located in Germany
           p:P1082 ?populationStatement.  # population property
  ?populationStatement ps:P1082 ?population;
                        pq:P585 ?year.  # point in time qualifier
  FILTER(YEAR(?year) >= 2010)
  BIND((?population - ?previousPopulation) / ?previousPopulation * 100 AS ?populationGrowth)
  FILTER(?populationGrowth >= 1)
